1	package auth
2	
3	import (
4		"context"
5		"fmt"
6		"time"
7	
8		"github.com/golang-jwt/jwt/v5"
9		"go.uber.org/zap"
10		"golang.org/x/crypto/bcrypt"
11		"google.golang.org/grpc"
12		"google.golang.org/grpc/codes"
13		"google.golang.org/grpc/status"
14	
15		"github.com/example/auth-service/internal/cache"
16	)
17	
18	type Service struct {
19		repo      Repository
20		cache     *cache.RedisCache
21		jwtSecret []byte
22		logger    *zap.Logger
23	}
24	
25	func NewService(repo Repository, cache *cache.RedisCache, secret string, logger *zap.Logger) *Service {
26		return &Service{repo: repo, cache: cache, jwtSecret: []byte(secret), logger: logger}
27	}
28	
29	func (s *Service) Register(srv *grpc.Server) {
30		// Register gRPC service implementation with the server
31	}
32	
33	func (s *Service) Login(ctx context.Context, email, password string) (string, error) {
34		user, err := s.repo.GetUserByEmail(ctx, email)
35		if err != nil {
36			return "", status.Error(codes.NotFound, "user not found")
37		}
38	
39		if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(password)); err != nil {
40			return "", status.Error(codes.Unauthenticated, "invalid credentials")
41		}
42	
43		token, err := s.generateToken(user.ID, user.Email)
44		if err != nil {
45			s.logger.Error("failed to generate token", zap.Error(err))
46			return "", status.Error(codes.Internal, "token generation failed")
47		}
48	
49		_ = s.cache.Set(ctx, fmt.Sprintf("token:%s", user.ID), token, 24*time.Hour)
50		return token, nil
51	}
52	
53	func (s *Service) CreateUser(ctx context.Context, email, password string) (string, error) {
54		hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
55		if err != nil {
56			return "", status.Error(codes.Internal, "failed to hash password")
57		}
58	
59		id, err := s.repo.CreateUser(ctx, email, string(hash))
60		if err != nil {
61			return "", status.Error(codes.AlreadyExists, "user already exists")
62		}
63		return id, nil
64	}
65	
66	func (s *Service) ValidateToken(ctx context.Context, tokenStr string) (string, error) {
67		token, err := jwt.Parse(tokenStr, func(t *jwt.Token) (interface{}, error) {
68			if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
69				return nil, fmt.Errorf("unexpected signing method: %v", t.Header["alg"])
70			}
71			return s.jwtSecret, nil
72		})
73		if err != nil || !token.Valid {
74			return "", status.Error(codes.Unauthenticated, "invalid token")
75		}
76	
77		claims, ok := token.Claims.(jwt.MapClaims)
78		if !ok {
79			return "", status.Error(codes.Internal, "invalid claims")
80		}
81		return claims["sub"].(string), nil
82	}
83	
84	func (s *Service) generateToken(userID, email string) (string, error) {
85		claims := jwt.MapClaims{
86			"sub":   userID,
87			"email": email,
88			"exp":   time.Now().Add(24 * time.Hour).Unix(),
89			"iat":   time.Now().Unix(),
90		}
91		return jwt.NewWithClaims(jwt.SigningMethodHS256, claims).SignedString(s.jwtSecret)
92	}
