5		"database/sql"
6	)
7	
8	type User struct {
9		ID           string
10		Email        string
11		PasswordHash string
12	}
13	
14	type Repository interface {
15		CreateUser(ctx context.Context, email, passwordHash string) (string, error)
16		GetUserByEmail(ctx context.Context, email string) (*User, error)
17	}
18	
19	type PostgresRepository struct {
20		db *sql.DB
21	}
22	
23	func NewPostgresRepository(db *sql.DB) *PostgresRepository {
24		return &PostgresRepository{db: db}
25	}
26	
27	func (r *PostgresRepository) CreateUser(ctx context.Context, email, passwordHash string) (string, error) {
28		var id string
29		err := r.db.QueryRowContext(ctx,
30			"INSERT INTO users (email, password_hash) VALUES ($1, $2) RETURNING id",
31			email, passwordHash,
32		).Scan(&id)
33		return id, err
34	}
35	
36	func (r *PostgresRepository) GetUserByEmail(ctx context.Context, email string) (*User, error) {
37		u := &User{}
38		err := r.db.QueryRowContext(ctx,
39			"SELECT id, email, password_hash FROM users WHERE email = $1",
40			email,
41		).Scan(&u.ID, &u.Email, &u.PasswordHash)
42		if err != nil {
43			return nil, err
44		}
45		return u, nil
46	}
