12	}
13	
14	func NewRedisCache(client *redis.Client) *RedisCache {
15		return &RedisCache{client: client}
16	}
17	
18	func (c *RedisCache) Set(ctx context.Context, key string, value string, ttl time.Duration) error {
19		return c.client.Set(ctx, key, value, ttl).Err()
20	}
21	
22	func (c *RedisCache) Get(ctx context.Context, key string) (string, error) {
23		return c.client.Get(ctx, key).Result()
24	}
25	
26	func (c *RedisCache) Delete(ctx context.Context, key string) error {
27		return c.client.Del(ctx, key).Err()
